export default function IndiaMapInteractive({ onStateSelect, mode = 'explore' }: Props) {
  const [selectedState, setSelectedState] = useState<string | null>(null)
  const [hoveredState, setHoveredState] = useState<string | null>(null)
  const [stats, setStats] = useState<{ totalCandidates: number; totalSeats: number } | null>(null)

  // Fetch live stats on mount and every 60s
  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await fetch('/api/stats')
        if (res.ok) {
          const data = await res.json()
          setStats(data)
        }
      } catch {
        // fallback silently
      }
    }
    fetchStats()
    const interval = setInterval(fetchStats, 60000)
    return () => clearInterval(interval)
  }, [])

  const handleStateClick = (stateName: string) => {
    setSelectedState(stateName)
    onStateSelect?.(stateName)
  }

  const stateData = selectedState
    ? CONSTITUENCIES.find((c) => c.state === selectedState)
    : null

  const getStateFill = (stateName: string) => {
    if (stateName === selectedState) return '#7F77DD'
    if (stateName === hoveredState) return '#fde04799'
    return '#1a1060'
  }

  const formatIN = (n: number) =>
    n.toLocaleString('en-IN')

  return (
    <div style={{ background: '#0f0b30' }} className="w-full">
      {/* Main layout: map + panel */}
      <div className="flex flex-col md:flex-row gap-0 md:gap-4 p-3 md:p-4">

        {/* SVG Map */}
        <div className="flex-1 min-w-0">
          <svg
            viewBox="0 0 1000 1136"
            style={{ width: '100%', maxHeight: '520px', display: 'block', cursor: 'pointer' }}
            preserveAspectRatio="xMidYMid meet"
          >
            <defs>
              <filter id="imap-glow">
                <feGaussianBlur stdDeviation="3" result="blur" />
                <feMerge>
                  <feMergeNode in="blur" />
                  <feMergeNode in="SourceGraphic" />
                </feMerge>
              </filter>
            </defs>
            {Object.entries(STATE_PATHS).map(([stateName, pathD]) => (
              <path
                key={stateName}
                data-state={stateName}
                d={pathD}
                fill={getStateFill(stateName)}
                stroke="#4a3fa0"
                strokeWidth={stateName === selectedState ? 1.5 : 0.8}
                strokeLinejoin="round"
                filter={stateName === selectedState ? 'url(#imap-glow)' : undefined}
                style={{ cursor: 'pointer', transition: 'fill 0.18s ease' }}
                onClick={() => handleStateClick(stateName)}
                onMouseEnter={() => setHoveredState(stateName)}
                onMouseLeave={() => setHoveredState(null)}
              >
                <title>{stateName}</title>
              </path>
            ))}
          </svg>
          <p className="text-center font-mono text-xs mt-1" style={{ color: '#7F77DD' }}>
            👆 Click any state to explore its constituencies
          </p>
        </div>

        {/* Right Panel */}
        <div
          className="w-full md:w-72 flex-shrink-0 rounded-xl border-2 overflow-hidden flex flex-col"
          style={{ borderColor: '#4a3fa0', background: '#100d3a', minHeight: 300, maxHeight: 520 }}
        >
          {!selectedState ? (
            <div className="flex flex-col items-center justify-center h-full p-6 text-center" style={{ minHeight: 300 }}>
              <div className="text-5xl mb-4">🗺️</div>
              <p className="font-black text-base text-white mb-1">Click any state</p>
              <p className="font-mono text-xs" style={{ color: '#7F77DD' }}>to explore its Lok Sabha constituencies</p>
            </div>
          ) : (
            <div className="flex flex-col h-full" style={{ maxHeight: 520 }}>
              {/* Panel header */}
              <div className="p-3 border-b flex-shrink-0" style={{ borderColor: '#4a3fa0', background: '#1a1060' }}>
                <div className="flex items-start justify-between gap-2">
                  <div>
                    <h3 className="font-black text-base text-white leading-tight">
                      {selectedState}
                    </h3>
                    <p className="font-mono text-xs" style={{ color: '#D4A017' }}>
                      {stateData ? stateData.seats.length : '—'} Lok Sabha seats
                    </p>
                  </div>
                  <button
                    onClick={() => setSelectedState(null)}
                    className="text-white/40 hover:text-white text-xl leading-none flex-shrink-0 mt-0.5"
                    aria-label="Close panel"
                  >
                    ×
                  </button>
                </div>
                {/* FILE HERE button */}
                <Link
                  href={`/file?state=${encodeURIComponent(selectedState)}`}
                  className="mt-2 block text-center py-1.5 px-3 rounded-lg font-black text-xs border-2 transition-colors"
                  style={{ borderColor: '#D4A017', color: '#D4A017', background: 'transparent' }}
                  onMouseOver={(e) => { e.currentTarget.style.background = '#D4A017'; e.currentTarget.style.color = '#000' }}
                  onMouseOut={(e) => { e.currentTarget.style.background = 'transparent'; e.currentTarget.style.color = '#D4A017' }}
                >
                  FILE HERE 🪳
                </Link>
              </div>

              {/* Constituency list */}
              <div className="overflow-y-auto flex-1 p-2">
                {stateData ? stateData.seats.map((seat) => (
                  <Link
                    key={seat.number}
                    href={`/seat/${seat.number}`}
                    onClick={() => onStateSelect?.(selectedState, seat.number)}
                    className="flex items-center justify-between px-3 py-2 rounded-lg mb-1 transition-colors group"
                    style={{ background: 'rgba(127,119,221,0.07)' }}
                    onMouseOver={(e) => { e.currentTarget.style.background = 'rgba(127,119,221,0.22)' }}
                    onMouseOut={(e) => { e.currentTarget.style.background = 'rgba(127,119,221,0.07)' }}
                  >
                    <span className="font-mono text-xs text-white/80 group-hover:text-white truncate pr-2">
                      {seat.name}
                    </span>
                    <span
                      className="font-black text-xs flex-shrink-0"
                      style={{ color: '#7F77DD' }}
                    >
                      #{seat.number}
                    </span>
                  </Link>
                )) : (
                  <p className="text-white/30 font-mono text-xs p-2">No constituencies found for this state.</p>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Live counter strip */}
      <div
        className="flex items-center justify-center gap-2 py-2 px-4 border-t font-mono text-xs"
        style={{ borderColor: '#4a3fa0', background: '#080620' }}
      >
        <span style={{ color: '#ef4444' }}>🔴</span>
        <span className="font-black" style={{ color: '#D4A017' }}>LIVE</span>
        <span className="text-white/60">·</span>
        <span className="text-white/80">
          {stats ? (
            <>
              <span className="font-black text-white">{formatIN(stats.totalCandidates)}</span>
              {' candidates · '}
              <span className="font-black text-white">{formatIN(stats.totalSeats || 543)}</span>
              {' seats contested'}
            </>
          ) : (
            '... candidates · 543 seats contested'
          )}
        </span>
      </div>
    </div>
  )
}
